SELECT COUNT(*) FROM lattes_p_prodbib AS lpp INNER JOIN lattes_prodbib AS lp ON lpp.fk_prodbib = lp.pk INNER JOIN servidor AS s ON lpp.fk_siape = s.pk_siape INNER JOIN qualis_rev AS qr ON lp.fk_revista = qr.pk WHERE LOWER(lp.tipo) = LOWER('artigo') AND LOWER(lp.natureza) = LOWER('completo') AND lp.ano = '2024' AND LOWER(qr.qualis) = LOWER('a4') AND LOWER(s.area_ingresso) = LOWER('administracao') AND LOWER(s.sigla_campus) = LOWER('uru') AND LOWER(s.genero) = LOWER('masculino')